SELECT TOP 1 COUNT(*) AS DAILY_COUNT 
FROM [COMMENTS] C 
WHERE C.[IsDeleted] = 0 
	AND C.[CREATED_DATE] > DATEADD(DAY, -1,
	GETDATE()) 
	AND C.[STATUS] = 'APPROVED' 